const e=["today","yesterday","thisWeek","lastWeek","thisMonth","lastMonth","thisYear","lastYear"];function o(a){const t=String(a||"").trim().match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);return t?`${t[3]}-${t[2].padStart(2,"0")}-${t[1].padStart(2,"0")}`:""}function s(a){const[t,r,n]=(a||"").split("-");return!t||!r||!n?"":`${n}/${r}/${t}`}function i(a){const t=String(a.getDate()).padStart(2,"0"),r=String(a.getMonth()+1).padStart(2,"0"),n=a.getFullYear();return`${t}/${r}/${n}`}function m(a){return e.map(t=>({key:t,label:a[t]||t}))}export{s as a,m as b,i as f,o as p};
